import java.io.*;
import java.util.*;

public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        String line;
        // Read first non‑empty line for T
        while ((line = br.readLine()) != null && line.trim().isEmpty()) {}
        if (line == null) return;
        int T = Integer.parseInt(line.trim());
        StringBuilder sb = new StringBuilder();
        for (int i = 0; i < T; i++) {
            String numLine;
            while ((numLine = br.readLine()) != null && numLine.trim().isEmpty()) {}
            if (numLine == null) break;
            int N = Integer.parseInt(numLine.trim());
            int d1 = N % 10;
            int d2 = (N / 10) % 10;
            int d3 = N / 100;
            sb.append("Digits in reverse order: ").append(d1).append(' ').append(d2).append(' ').append(d3);
            if (i != T - 1) sb.append('\n');
        }
        System.out.print(sb.toString());
    }
}

